text:
{
  "formal_minutes": {
    "decisions": [
      "릴리스는 내부 규칙 기반으로 금요일 15:00 KST를 공개 릴리스 타깃으로 두되, smoke 테스트가 통과했을 때만 유효하다.",
      "`smoke-theme-pack.mjs`에서 `packageName` 불일치(`packageName mismatch`)를 무시하지 않는다. 불일치가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트 리뷰를 검토한다.",
      "Minjun이 금요일 10:00 KST까지 smoke 테스트를 재실행하고 결과를 공유한다(확인된 액션).",
      "Doyun이 금요일 12:00 KST까지 실패 원인 트리아지 노트를 `action_items.md`에 작성한다(확인된 액션).",
      "Hara가 Minjun의 smoke 결과 공유 후 생성된 tarball 경로를 확인한다."
    ],
    "rejected_proposals": [
      "Hara가 제안한 `smoke-theme-pack.mjs`에서 `packageName` 불일치를 무조건 무시하는 제안은 반려됨."
    ],
    "internal_stretch_goals": [
      "수요일 공개 릴리스 시도안은 내부 stretch goal로 남겨두되, 확정 릴리스 타깃은 아님."
    ],
    "non_decisions": [
      "README 설치 절차 검토는 목요일 가능 여부로 언급되었으나, 담당자/최종 책임자는 확정되지 않음."
    ],
    "risks": [
      "생성 tarball 경로가 잘못되면 릴리스가 지연될 수 있음.",
      "README 설치 단계가 오래되면 릴리스 노트가 사용자에게 오해를 줄 수 있음."
    ],
    "open_questions": [
      "최종 릴리스 승인 권한자는 누구인가?",
      "릴리스 노트에 내부 수요일 stretch goal을 명시해야 하는지 여부."
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "smoke 테스트 재실행 후 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "직접적 발언"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트를 `action_items.md`에 작성",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "직접적 발언"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 smoke 결과 공유 후 생성된 tarball 경로 확인",
      "due": "명시된 마감일 없음(공유 후 즉시 수행)",
      "status": "확정",
      "source_certainty": "직접적 발언"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "smoke 테스트 재실행 결과가 pass/fail인지와 실패 시 상세 이슈 분류를 확인한다.",
      "Doyun의 `action_items.md` 트리아지 노트 반영 상태를 확인한다.",
      "Hara가 확인한 tarball 경로가 실제 배포/검증 경로와 일치하는지 크로스체크한다.",
      "README 설치 가이드의 최신성(필요한 경우 owner 지정 포함)을 확정한다.",
      "최종 릴리스 승인 권한자와 Wednesday stretch goal 노출 여부를 별도 승인 단계에서 확정한다."
    ],
    "what_not_to_invent": [
      "고객명, 예산, 보안 이슈, 장애, 법무 승인, 소유자(미지정 항목), 마감일(명시되지 않은 항목)을 임의로 추가하지 않는다.",
      "외부 파트너명이나 조직 내 미공개 관계자 정보를 추가하지 않는다.",
      "golden/reference 결과를 가정해 확정값으로 채우지 않는다."
    ]
  },
  "non_invention_rules": [
    "참고 입력에 없는 사실은 생성하지 않는다.",
    "고객/파트너, 예산, 보안 사고, 운영 장애, 법무 승인, 책임자, 마감일은 텍스트에 명시되지 않은 경우 추정 금지.",
    "smoke 통과 전과 수요일 제안은 조건부/내부 항목으로 구분해 기록한다.",
    "모든 액션 아이템은 owner/task/due/status/source_certainty 형식을 유지한다.",
    "열린 질문은 ‘결정되지 않음’으로만 표기한다."
  ]
}
